import{_ as t,o,c as d,a2 as a}from"./chunks/framework.Bix3-HpO.js";const p=JSON.parse('{"title":"Plugin Shortcodes","description":"DinOdds Plugin Shortcodes","frontmatter":{"title":"Plugin Shortcodes","description":"DinOdds Plugin Shortcodes","weight":50,"extra":{"order":50},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/dinodds/plugin-shortcodes"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/dinodds/plugin-shortcodes"}],["meta",{"property":"og:title","content":"Plugin Shortcodes"}],["meta",{"property":"og:description","content":"DinOdds Plugin Shortcodes"}],["meta",{"name":"twitter:title","content":"Plugin Shortcodes"}],["meta",{"name":"twitter:description","content":"DinOdds Plugin Shortcodes"}]]},"headers":[],"relativePath":"docs/dinodds/plugin-shortcodes.md","filePath":"docs/dinodds/plugin-shortcodes.md"}'),s={name:"docs/dinodds/plugin-shortcodes.md"};function l(i,e,r,n,c,h){return o(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="plugin-shortcodes" tabindex="-1">Plugin Shortcodes <a class="header-anchor" href="#plugin-shortcodes" aria-label="Permalink to &quot;Plugin Shortcodes&quot;">​</a></h1><p>DinOdds lets you display betting odds tables anywhere on your site using a simple <code>[odds]</code> shortcode. You can generate these shortcodes from the admin interface and paste them into posts, pages, or widgets.</p><h2 id="shortcode-overview" tabindex="-1">Shortcode Overview <a class="header-anchor" href="#shortcode-overview" aria-label="Permalink to &quot;Shortcode Overview&quot;">​</a></h2><p>The base shortcode format is:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[odds league=&quot;&quot; bookies=&quot;&quot; style=&quot;&quot; layout=&quot;&quot; class=&quot;&quot; type=&quot;&quot; selector=&quot;&quot; away=&quot;&quot; home=&quot;&quot;]</span></span></code></pre></div><p>At a minimum, you must choose a <strong>league</strong> and <strong>bookies</strong>. All other attributes are optional and can be configured via the shortcode generator.</p><h2 id="shortcode-types" tabindex="-1">Shortcode Types <a class="header-anchor" href="#shortcode-types" aria-label="Permalink to &quot;Shortcode Types&quot;">​</a></h2><p><code>💁 since version 1.3</code> there are two main ways to display odds:</p><ul><li><p><strong>All League Odds</strong> Display an odds table for all <em>upcoming</em> matches in a given league.</p></li><li><p><strong>Single Match Odds</strong> Display odds for a single match in that league by specifying both <code>away</code> and <code>home</code> team names.</p></li></ul><p>If <strong>both</strong> <code>away</code> and <code>home</code> are provided, DinOdds will attempt to find and display that single upcoming match. If either is missing, DinOdds falls back to the <strong>All League Odds</strong> view.</p><h3 id="shortcode-styles" tabindex="-1">Shortcode Styles <a class="header-anchor" href="#shortcode-styles" aria-label="Permalink to &quot;Shortcode Styles&quot;">​</a></h3><p><code>💁 since version 1.5</code> there are two layout styles you can use for displaying odds:</p><ul><li><strong>Style 1 (Default)</strong>: Navigate left and right using arrows</li><li><strong>Style 2</strong>: Navigate left and right using the mouse and/or keyboard</li></ul><h3 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h3><ul><li><p>All league odds (default style and layout):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[odds league=&quot;nfl&quot;]</span></span></code></pre></div></li><li><p>All league odds with selected bookies, style 2, without odds type selector:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[odds league=&quot;nfl&quot; bookies=&quot;mybookie,betonline&quot; style=&quot;2&quot; selector=&quot;false&quot;]</span></span></code></pre></div></li><li><p>Single match odds for a specific game:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[odds league=&quot;nfl&quot; away=&quot;Buffalo Bills&quot; home=&quot;Houston Texans&quot;]</span></span></code></pre></div></li></ul><h2 id="shortcode-generator" tabindex="-1">Shortcode Generator <a class="header-anchor" href="#shortcode-generator" aria-label="Permalink to &quot;Shortcode Generator&quot;">​</a></h2><p>You don’t need to write attributes by hand. Use the shortcode generator in the DinOdds settings screen:</p><ol><li><strong>Select League</strong> – Choose a league from the dropdown. This is required.</li><li><strong>Select Bookies</strong> – Choose one or more bookies: <ul><li>Hold the <strong>Command (macOS)</strong> or <strong>Ctrl (Windows/Linux)</strong> key to select multiple.</li><li>Leave all unselected to display <strong>all available bookies</strong>.</li></ul></li><li><strong>Select Style</strong> – Choose the table style: <ul><li><code>1</code> – Default style.</li><li><code>2</code> – Alternative table layout (where available).</li></ul></li><li><strong>Select Links Layout</strong> – Choose how bookie links are displayed: <ul><li><code>top</code> – Links above the table (default).</li><li><code>inline</code> – Links displayed inline beneath the odds.</li></ul></li><li><strong>Select Odds Type</strong> – Choose the default odds type: <ul><li><code>spread</code> (default)</li><li><code>moneyline</code></li><li><code>total</code></li></ul></li><li><strong>Display Type Selector</strong> – Decide whether to show the odds type selector: <ul><li><code>true</code> – Show the selector (default).</li><li><code>false</code> – Hide the selector.</li></ul></li><li><strong>Custom CSS Class (optional)</strong> – Add an extra CSS class that you can target in your theme styles.</li><li><strong>Away / Home Team (optional)</strong> – For <strong>Single Match Odds</strong>: <ul><li>Set <code>away</code> and <code>home</code> team names exactly as they appear in the data feed.</li><li>Leave both empty to show all league odds.</li></ul></li></ol><p>As you change these options, the generator builds the shortcode for you. Use the <strong>“Copy shortcode to clipboard”</strong> button and paste it wherever you want the odds table to appear.</p><h2 id="shortcode-attributes" tabindex="-1">Shortcode Attributes <a class="header-anchor" href="#shortcode-attributes" aria-label="Permalink to &quot;Shortcode Attributes&quot;">​</a></h2><p>Here is a quick reference for all supported attributes:</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Required</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>league</code></td><td>Yes</td><td>League identifier whose odds you want to display.</td><td>—</td></tr><tr><td><code>bookies</code></td><td>No</td><td>Comma-separated list of bookies. Leave empty to show all bookies.</td><td>All bookies</td></tr><tr><td><code>style</code></td><td>No</td><td>Table style variant (<code>1</code> or <code>2</code>).</td><td><code>1</code></td></tr><tr><td><code>layout</code></td><td>No</td><td>Layout for bookie links: <code>top</code> or <code>inline</code>.</td><td><code>top</code></td></tr><tr><td><code>type</code></td><td>No</td><td>Default odds type: <code>spread</code>, <code>moneyline</code>, or <code>total</code>.</td><td><code>spread</code></td></tr><tr><td><code>selector</code></td><td>No</td><td>Whether to display the odds type selector: <code>true</code> or <code>false</code>.</td><td><code>true</code></td></tr><tr><td><code>class</code></td><td>No</td><td>Extra CSS class added to the wrapper for custom styling.</td><td>—</td></tr><tr><td><code>away</code></td><td>No</td><td>Away team name for a single match view.</td><td>—</td></tr><tr><td><code>home</code></td><td>No</td><td>Home team name for a single match view.</td><td>—</td></tr></tbody></table><p>When there are <strong>no upcoming matches</strong> for the chosen league (or no matching single game for the given teams), DinOdds will display a dedicated “no matches available” view instead of leaving the page blank.</p>',23)])])}const g=t(s,[["render",l]]);export{p as __pageData,g as default};
